//
// Hand-authored novel command: `publish resume <slug>`. Completes a publish
// that uploaded its files but never finalized. Header intentionally a plain
// copyright line (no "Generated by ... DO NOT EDIT") so a future regen-merge
// classifies this as hand-authored and preserves it.

package cli

import (
	"fmt"
	"strings"

	"github.com/spf13/cobra"
)

func newNovelPublishResumeCmd(flags *rootFlags) *cobra.Command {
	var flagDB string

	cmd := &cobra.Command{
		Use:   "resume <slug>",
		Short: "Finalize a locally-recorded publish that uploaded files but never finalized",
		Example: strings.Trim(`
  here-now-pp-cli publish resume my-site
  here-now-pp-cli publish resume my-site --json
`, "\n"),
		Annotations: map[string]string{"mcp:read-only": "false"},
		RunE: func(cmd *cobra.Command, args []string) error {
			if len(args) == 0 {
				return cmd.Help()
			}
			if dryRunOK(flags) {
				return nil
			}
			slug := args[0]

			db, err := openHereNowStore(cmd.Context(), flagDB)
			if err != nil {
				return err
			}
			defer db.Close()

			state, err := db.GetPublishState(slug)
			if err != nil {
				return err
			}
			if state == nil {
				return notFoundErr(fmt.Errorf("no local publish record for %q; nothing to resume\nhint: 'publish resume' only completes a publish this CLI started but did not finalize. Run 'here-now-pp-cli claims' to see locally-recorded publishes", slug))
			}
			if state.Finalized {
				return printResumeResult(cmd, flags, slug, "already_finalized",
					fmt.Sprintf("publish %q is already finalized; nothing to resume", slug))
			}

			c, err := flags.newClient()
			if err != nil {
				return err
			}
			if ferr := finalizePublish(cmd.Context(), c, slug, state.VersionID); ferr != nil {
				return classifyAPIError(ferr, flags)
			}
			if merr := db.MarkFinalized(slug); merr != nil {
				return merr
			}
			return printResumeResult(cmd, flags, slug, "finalized",
				fmt.Sprintf("resumed and finalized publish %q (version %s)", slug, state.VersionID))
		},
	}

	cmd.Flags().StringVar(&flagDB, "db", "", "Database path (default: ~/.local/share/here-now-pp-cli/data.db)")
	return cmd
}

// printResumeResult emits the resume outcome as JSON or a human line.
func printResumeResult(cmd *cobra.Command, flags *rootFlags, slug, status, message string) error {
	if flags.asJSON || !isTerminal(cmd.OutOrStdout()) {
		return printJSONFiltered(cmd.OutOrStdout(), map[string]any{
			"slug":    slug,
			"status":  status,
			"message": message,
		}, flags)
	}
	fmt.Fprintln(cmd.OutOrStdout(), message)
	return nil
}
